sys_security_acl.script:
answer = true;
try{
	var currentSysId = gs.action.getGlideURI().get("sys_id");
	if(currentSysId != '' && currentSysId != -1 && currentSysId != null ){
		var gr = new GlideRecord("x_153465_discovert_route_task_instance");
		if(gr.get("sys_id", currentSysId)){
			var currentUser = gs.getUserID();
			if(gr.u_task_requester == currentUser || gr.assigned_to == currentUser){
				answer = true;
			}else{
				answer = false;
			}
		}
	}
}catch(e){
	var context = "Tasker | x_153465_discovert_route_task_instance.create";
	gs.error(context + " : " + e.message);
}
